const employee = $('Prepare Employee Data').first().json;
const googleResult = $('Create Google Account').first().json;
const slackResult = $('Invite to Slack').first().json;
const notionResult = $('Create Notion Onboarding').first().json;

const provisioningResults = {
  onboardingId: employee.onboardingId,
  employee: {
    name: employee.firstName + ' ' + employee.lastName,
    workEmail: employee.workEmail,
    personalEmail: employee.personalEmail,
    department: employee.department,
    jobTitle: employee.jobTitle,
    startDate: employee.startDate,
    managerId: employee.managerId
  },
  accounts: {
    google: { status: googleResult.id ? 'created' : 'pending', email: employee.workEmail },
    slack: { status: slackResult.ok ? 'invited' : 'pending' },
    notion: { status: notionResult.id ? 'created' : 'pending', pageUrl: notionResult.url || '' }
  },
  provisionedAt: new Date().toISOString()
};

return [{ json: provisioningResults }];

parameters.text:
=Create a personalized welcome package for a new employee:

Employee Name: {{ $json.employee.name }}
Department: {{ $json.employee.department }}
Job Title: {{ $json.employee.jobTitle }}
Start Date: {{ $json.employee.startDate }}

Generate:
1. A warm welcome message (2-3 sentences)
2. First week suggested schedule with 5 key activities
3. 3 tips for success in their role

Format as JSON with keys: welcomeMessage, firstWeekSchedule (array), successTips (array)

parameters.jsCode:
const provisionData = $('Compile Provisioning Results').first().json;
const aiResponse = $input.first().json;

let aiContent = {};
try {
  const outputText = aiResponse.output || '{}';
  const jsonMatch = outputText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    aiContent = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  aiContent = {
    welcomeMessage: 'Welcome to the team! We are excited to have you.',
    firstWeekSchedule: ['Day 1: Orientation', 'Day 2: Team introductions', 'Day 3: System setup', 'Day 4: Training', 'Day 5: Project overview'],
    successTips: ['Ask questions', 'Take notes', 'Connect with colleagues']
  };
}

const welcomePackage = {
  ...provisionData,
  welcomeContent: aiContent,
  emailSubject: 'Welcome to ' + provisionData.employee.department + '! - ' + provisionData.employee.name,
  emailBody: 'Dear ' + provisionData.employee.name + ',\n\n' + (aiContent.welcomeMessage || 'Welcome!') + '\n\nYour work email: ' + provisionData.employee.workEmail + '\n\nFirst Week Schedule:\n' + (aiContent.firstWeekSchedule || []).map(function(item, i) { return (i + 1) + '. ' + item; }).join('\n') + '\n\nTips for Success:\n' + (aiContent.successTips || []).map(function(item) { return '- ' + item; }).join('\n') + '\n\nBest regards,\nHR Team'
};

return [{ json: welcomePackage }];

